2837           VPInstruction::FirstActiveLane, {CondToEarlyExit}, nullptr,
2838           "first.active.lane");
2839       IncomingFromEarlyExit = EarlyExitB.createNaryOp(
2840           VPInstruction::ExtractLane, {FirstActiveLane, IncomingFromEarlyExit},
