2905 /// This function tries convert extended in-loop reductions to
2906 /// VPExpressionRecipe and clamp the \p Range if it is beneficial
2907 /// and valid. The created VPExpressionRecipe must be decomposed to its
2908 /// constituent recipes before execution. Patterns of the
2909 /// VPExpressionRecipe:
2910 ///   reduce.add(mul(...)),
2911 ///   reduce.add(mul(ext(A), ext(B))),
2912 ///   reduce.add(ext(mul(ext(A), ext(B)))).
2913 static VPExpressionRecipe *
2914 tryToMatchAndCreateMulAccumulateReduction(VPReductionRecipe *Red,
2915                                           VPCostContext &Ctx, VFRange &Range) {
2916   using namespace VPlanPatternMatch;
2917 
2918   unsigned Opcode = RecurrenceDescriptor::getOpcode(Red->getRecurrenceKind());
2919   if (Opcode != Instruction::Add)
2920     return nullptr;
2921 
2922   Type *RedTy = Ctx.Types.inferScalarType(Red);
2923 
2924   // Clamp the range if using multiply-accumulate-reduction is profitable.
2925   auto IsMulAccValidAndClampRange =
2926       [&](bool isZExt, VPWidenRecipe *Mul, VPWidenCastRecipe *Ext0,
2927           VPWidenCastRecipe *Ext1, VPWidenCastRecipe *OuterExt) -> bool {
2928     return LoopVectorizationPlanner::getDecisionAndClampRange(
2929         [&](ElementCount VF) {
2930           TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;
2931           Type *SrcTy =
2932               Ext0 ? Ctx.Types.inferScalarType(Ext0->getOperand(0)) : RedTy;
2933           auto *SrcVecTy = cast<VectorType>(toVectorTy(SrcTy, VF));
2934           InstructionCost MulAccCost =
2935               Ctx.TTI.getMulAccReductionCost(isZExt, RedTy, SrcVecTy, CostKind);
2936           InstructionCost MulCost = Mul->computeCost(VF, Ctx);
2937           InstructionCost RedCost = Red->computeCost(VF, Ctx);
2938           InstructionCost ExtCost = 0;
2939           if (Ext0)
2940             ExtCost += Ext0->computeCost(VF, Ctx);
2941           if (Ext1)
2942             ExtCost += Ext1->computeCost(VF, Ctx);
2943           if (OuterExt)
2944             ExtCost += OuterExt->computeCost(VF, Ctx);
2945 
2946           return MulAccCost.isValid() &&
2947                  MulAccCost < ExtCost + MulCost + RedCost;
2948         },
2949         Range);
2950   };
2951 
2952   VPValue *VecOp = Red->getVecOp();
2953   VPValue *A, *B;
2954   // Try to match reduce.add(mul(...)).
2955   if (match(VecOp, m_Mul(m_VPValue(A), m_VPValue(B)))) {
2956     auto *RecipeA =
2957         dyn_cast_if_present<VPWidenCastRecipe>(A->getDefiningRecipe());
2958     auto *RecipeB =
2959         dyn_cast_if_present<VPWidenCastRecipe>(B->getDefiningRecipe());
2960     auto *Mul = cast<VPWidenRecipe>(VecOp->getDefiningRecipe());
2961 
2962     // Match reduce.add(mul(ext, ext)).
2963     if (RecipeA && RecipeB &&
2964         (RecipeA->getOpcode() == RecipeB->getOpcode() || A == B) &&
2965         match(RecipeA, m_ZExtOrSExt(m_VPValue())) &&
2966         match(RecipeB, m_ZExtOrSExt(m_VPValue())) &&
2967         IsMulAccValidAndClampRange(RecipeA->getOpcode() ==
2968                                        Instruction::CastOps::ZExt,
2969                                    Mul, RecipeA, RecipeB, nullptr)) {
2970       return new VPExpressionRecipe(RecipeA, RecipeB, Mul, Red);
2971     }
2972     // Match reduce.add(mul).
2973     if (IsMulAccValidAndClampRange(true, Mul, nullptr, nullptr, nullptr))
2974       return new VPExpressionRecipe(Mul, Red);
2975   }
2976   // Match reduce.add(ext(mul(ext(A), ext(B)))).
2977   // All extend recipes must have same opcode or A == B
2978   // which can be transform to reduce.add(zext(mul(sext(A), sext(B)))).
2979   if (match(VecOp, m_ZExtOrSExt(m_Mul(m_ZExtOrSExt(m_VPValue()),
2980                                       m_ZExtOrSExt(m_VPValue()))))) {
2981     auto *Ext = cast<VPWidenCastRecipe>(VecOp->getDefiningRecipe());
2982     auto *Mul = cast<VPWidenRecipe>(Ext->getOperand(0)->getDefiningRecipe());
2983     auto *Ext0 =
2984         cast<VPWidenCastRecipe>(Mul->getOperand(0)->getDefiningRecipe());
2985     auto *Ext1 =
2986         cast<VPWidenCastRecipe>(Mul->getOperand(1)->getDefiningRecipe());
2987     if ((Ext->getOpcode() == Ext0->getOpcode() || Ext0 == Ext1) &&
2988         Ext0->getOpcode() == Ext1->getOpcode() &&
2989         IsMulAccValidAndClampRange(Ext0->getOpcode() ==
2990                                        Instruction::CastOps::ZExt,
2991                                    Mul, Ext0, Ext1, Ext)) {
2992       auto *NewExt0 = new VPWidenCastRecipe(
2993           Ext0->getOpcode(), Ext0->getOperand(0), Ext->getResultType(), *Ext0,
2994           Ext0->getDebugLoc());
2995       NewExt0->insertBefore(Ext0);
2996 
2997       VPWidenCastRecipe *NewExt1 = NewExt0;
2998       if (Ext0 != Ext1) {
2999         NewExt1 = new VPWidenCastRecipe(Ext1->getOpcode(), Ext1->getOperand(0),
3000                                         Ext->getResultType(), *Ext1,
3001                                         Ext1->getDebugLoc());
3002         NewExt1->insertBefore(Ext1);
3003       }
3004       Mul->setOperand(0, NewExt0);
3005       Mul->setOperand(1, NewExt1);
3006       Red->setOperand(1, Mul);
3007       return new VPExpressionRecipe(NewExt0, NewExt1, Mul, Red);
3008     }
3009   }
3010   return nullptr;
3011 }
