2808   VPBlockUtils::connectBlocks(NewMiddle, VectorEarlyExitVPBB);
2809   NewMiddle->swapSuccessors();
2810 
2811   VPBlockUtils::connectBlocks(VectorEarlyExitVPBB, EarlyExitVPBB);
