2840           VPInstruction::ExtractLane, {FirstActiveLane, IncomingFromEarlyExit},
2841           nullptr, "early.exit.value");
2842       ExitIRI->setOperand(EarlyExitIdx, IncomingFromEarlyExit);
2843     }
2844   }
2845   MiddleBuilder.createNaryOp(VPInstruction::BranchOnCond, {IsEarlyExitTaken});
